package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetCommentMarkerWhenSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker);
        assertEquals(Character.valueOf('#'), commentMarker);
    }

    @Test
    void testGetCommentMarkerWhenNull() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        Character commentMarker = format.getCommentMarker();
        assertNull(commentMarker);
    }

    @Test
    void testGetCommentMarkerDefault() {
        Character commentMarker = CSVFormat.DEFAULT.getCommentMarker();
        assertNull(commentMarker);
    }
}
